import{c as n,Z as i,Q as l,j as o,g as t,n as r,o as s,m as g}from"./chunks/framework.qjzPVSkb.js";const b=JSON.parse('{"title":"Agent","description":"能自主理解目标、分解任务、选择工具、执行并反思的 AI 智能体——LLM + 工具调用 + 规划循环","frontmatter":{"title":"Agent","description":"能自主理解目标、分解任务、选择工具、执行并反思的 AI 智能体——LLM + 工具调用 + 规划循环","difficulty":"intermediate"},"headers":[],"relativePath":"terms/agent.md","filePath":"terms/agent.md"}'),d={name:"terms/agent.md"};function h(c,e,u,A,m,p){const a=i("DifficultyBadge");return l(),o("div",null,[e[0]||(e[0]=t("h1",{id:"agent",tabindex:"-1"},[r("Agent "),t("a",{class:"header-anchor",href:"#agent","aria-label":'Permalink to "Agent"'},"​")],-1)),s(a,{level:"intermediate"}),e[1]||(e[1]=g('<h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>Agent（智能体）是一种能够<strong>自主理解目标、规划步骤、调用工具、执行任务并根据结果进行反思调整</strong>的 AI 系统。它的核心公式是 <strong>Agent = LLM + 工具调用 + 规划 + 记忆</strong>，它让 LLM 从&quot;被动回答&quot;升级为&quot;主动做事&quot;。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>LLM 像一个知识渊博的图书管理员——你问什么它答什么，但不会主动站起来去找书。Agent 则像一个能干的私人助理——你只需要说&quot;帮我订下周五去上海的机票，要靠过道的座位，再给酒店发邮件确认入住&quot;，它会自己拆解成&quot;查航班→比较价格→订票→选座→写邮件→发送&quot;等一系列步骤，每一步调用合适的工具（订票 API、邮件客户端），中间遇到问题（比如过道座没了）还会自己调整方案（改靠窗？换航班？），最后向你汇报结果。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>Agent 系统的经典架构包含四个核心组件：</p><ol><li><strong>大语言模型（LLM）</strong>：作为 Agent 的&quot;大脑&quot;，负责任务理解、推理和决策</li><li><strong>规划（Planning）</strong>：将复杂目标分解为可执行的子任务序列。常用技术包括 ReAct（Reasoning + Acting）、Plan-and-Solve、Tree of Thoughts 等</li><li><strong>工具（Tools）</strong>：Agent 可以调用的外部能力，通过 <a href="/ai-knowledge/terms/function-calling.html">Function Calling</a> 实现。常见工具有搜索 API、代码执行器、数据库查询、文件操作等</li><li><strong>记忆（Memory）</strong>：存储中间结果和历史经验。分为短期记忆（当前会话上下文）和长期记忆（持久化的知识库/经验）</li></ol><p>Agent 的执行模式通常遵循 <strong>观察-思考-行动（Observe-Think-Act）循环</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户目标 → Agent 分析 → 制定步骤 → 调用工具 → 观察结果 → 反思调整 → 继续执行 → 完成任务</span></span></code></pre></div><p>常见的 Agent 框架包括 LangChain Agent、AutoGPT、CrewAI、MetaGPT 等。多 Agent 协作（Multi-Agent）也是当前研究热点，让多个专业 Agent 像团队一样协作完成复杂任务。</p><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/function-calling.html">Function Calling</a> —— Agent 调用外部工具的原子能力</li><li><a href="/ai-knowledge/terms/cot.html">思维链 (CoT)</a> —— Agent 进行任务规划和推理的关键技术</li><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— Agent 的核心决策引擎</li><li><a href="/ai-knowledge/terms/rag.html">RAG</a> —— Agent 获取外部知识进行决策的重要途径</li></ul><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>Lilian Weng 的经典博客：<a href="https://lilianweng.github.io/posts/2023-06-23-agent/" target="_blank" rel="noreferrer">LLM Powered Autonomous Agents</a></li><li>ReAct 论文：<a href="https://arxiv.org/abs/2210.03629" target="_blank" rel="noreferrer">ReAct: Synergizing Reasoning and Acting in Language Models</a></li><li><a href="/ai-knowledge/dev/agent-intro.html">Agent 核心概念</a> — 动手实现一个 Agent</li><li><a href="/ai-knowledge/dev/build-agent.html">构建你的第一个 Agent</a> — 从零到一的完整代码</li></ul>',14))])}const _=n(d,[["render",h]]);export{b as __pageData,_ as default};
